mapper.select:
SELECT i.inventory_id, i.product_id, i.warehouse_id, i.qty_on_hand, i.qty_reserved, i.lot_no, i.expiry_date, DATE_FORMAT(i.last_updated, '%Y-%m-%d %H:%i') AS last_updated, p.product_code, p.product_name, p.unit, p.reorder_point, w.warehouse_code, w.warehouse_name FROM INVENTORY i INNER JOIN PRODUCT p ON i.product_id = p.product_id INNER JOIN WAREHOUSE w ON i.warehouse_id = w.warehouse_id
AND (p.product_name LIKE CONCAT('%', #{keyword}, '%') OR p.product_code LIKE CONCAT('%', #{keyword}, '%'))
AND i.warehouse_id = #{warehouseId}
AND w.type = #{warehouseType}
ORDER BY p.product_code, w.warehouse_code
